.darma-loader-darma-custom-690 {
  color: var(--loader-color, #6366f1);
  --loader-secondary-color: var(--loader-secondary-color, #a5b4fc);
  --loader-bg: var(--loader-bg, #ffffff);
width: 45px;
aspect-ratio: 1;
--c:no-repeat linear-gradient(currentColor 0 0);
background: var(--c), var(--c), var(--c);
animation:
darma-loader-darma-custom-690-l16-1 1s infinite,
darma-loader-darma-custom-690-l16-2 1s infinite;
}
@keyframes darma-loader-darma-custom-690-l16-1 {
0%,100% {background-size:20% 100%}
33%,66% {background-size:20% 40%}
}
@keyframes darma-loader-darma-custom-690-l16-2 {
0%,33% {background-position: 0 0 ,50% 100%,100% 0}
66%,100% {background-position: 0 100%,50% 0 ,100% 100%}
}

